import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";
import api from "../utils/api";
import { CATEGORY_OPTIONS } from "../utils/categories";

const STATUS_LABEL = {
  pending: "Хүлээгдэж буй",
  confirmed: "Баталгаажсан",
  cancelled: "Цуцлагдсан",
  completed: "Дууссан",
};

function parseNumber(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

export default function AdminPage() {
  const { user, canManagePlaces } = useAuth();
  const nav = useNavigate();

  const [places, setPlaces] = useState([]);
  const [placeId, setPlaceId] = useState("");
  const [place, setPlace] = useState(null);
  const [services, setServices] = useState([]);
  const [staffs, setStaffs] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [bookingLoading, setBookingLoading] = useState(false);
  const [bookingStatus, setBookingStatus] = useState("all");

  const [savingPlace, setSavingPlace] = useState(false);
  const [msg, setMsg] = useState("");
  const [err, setErr] = useState("");

  const [serviceForm, setServiceForm] = useState({
    name: "",
    duration: 30,
    price: 0,
  });
  const [staffForm, setStaffForm] = useState({
    name: "",
    role: "barber",
    profileImage: "",
  });
  const [tableForm, setTableForm] = useState({
    name: "",
    type: "regular",
    row: "A",
    col: 1,
    capacity: 4,
  });

  useEffect(() => {
    if (!user || !canManagePlaces) {
      nav("/");
      return;
    }

    api.get("/places/mine").then(({ data }) => {
      setPlaces(data.data || []);
      if (data.data?.[0]) setPlaceId(data.data[0]._id);
    });
  }, [user, canManagePlaces, nav]);

  useEffect(() => {
    if (!placeId) return;
    loadPlace(placeId);
  }, [placeId]);

  const loadPlace = async (id) => {
    setErr("");
    setMsg("");
    try {
      const { data } = await api.get(`/places/${id}`);
      setPlace(data.data);
      setServices(data.data.services || []);
      setStaffs(data.data.staffs || []);
      loadBookings(id, bookingStatus);
    } catch (e) {
      setErr(e.response?.data?.message || "Админ мэдээлэл ачаалж чадсангүй");
    }
  };

  const loadBookings = async (id = placeId, status = bookingStatus) => {
    if (!id) return;
    setBookingLoading(true);
    try {
      const q = new URLSearchParams({ placeId: id });
      if (status !== "all") q.set("status", status);
      const { data } = await api.get(`/bookings/admin?${q.toString()}`);
      setBookings(data.data || []);
    } catch {
      setBookings([]);
    }
    setBookingLoading(false);
  };

  const confirmBooking = async (id) => {
    await api.put(`/bookings/${id}/confirm`);
    loadBookings();
  };

  const cancelBooking = async (id) => {
    if (!window.confirm("Энэ захиалгыг цуцлах уу?")) return;
    await api.put(`/bookings/${id}/cancel`);
    loadBookings();
  };

  const savePlace = async () => {
    if (!place) return;
    setSavingPlace(true);
    setErr("");
    setMsg("");

    try {
      const payload = {
        name: place.name,
        category: place.category,
        description: place.description,
        address: place.address,
        phone: place.phone,
        location: {
          lat: parseNumber(place.location?.lat),
          lng: parseNumber(place.location?.lng),
        },
        images: place.images || [],
        tables: place.tables || [],
      };

      await api.put(`/places/${place._id}`, payload);
      await loadPlace(place._id);
      setMsg("Газрын мэдээлэл амжилттай хадгалагдлаа");
    } catch (e) {
      setErr(e.response?.data?.message || "Хадгалах үед алдаа гарлаа");
    }

    setSavingPlace(false);
  };

  const addService = async () => {
    if (!place) return;
    try {
      await api.post("/services", {
        placeId: place._id,
        name: serviceForm.name,
        duration: parseNumber(serviceForm.duration, 30),
        price: parseNumber(serviceForm.price, 0),
      });
      setServiceForm({ name: "", duration: 30, price: 0 });
      loadPlace(place._id);
    } catch (e) {
      setErr(e.response?.data?.message || "Үйлчилгээ нэмэхэд алдаа гарлаа");
    }
  };

  const removeService = async (id) => {
    await api.delete(`/services/${id}`);
    loadPlace(place._id);
  };

  const addStaff = async () => {
    if (!place) return;
    try {
      await api.post("/staff", {
        placeId: place._id,
        name: staffForm.name,
        role: staffForm.role,
        profileImage: staffForm.profileImage,
      });
      setStaffForm({ name: "", role: "barber", profileImage: "" });
      loadPlace(place._id);
    } catch (e) {
      setErr(e.response?.data?.message || "Ажилтан нэмэхэд алдаа гарлаа");
    }
  };

  const removeStaff = async (id) => {
    await api.delete(`/staff/${id}`);
    loadPlace(place._id);
  };

  const addTable = () => {
    if (!place) return;
    setPlace({
      ...place,
      tables: [...(place.tables || []), { ...tableForm, _id: `${Date.now()}` }],
    });
    setTableForm({ name: "", type: "regular", row: "A", col: 1, capacity: 4 });
  };

  const removeTable = (id) => {
    setPlace({
      ...place,
      tables: (place.tables || []).filter((t) => t._id !== id),
    });
  };

  const categoryOptions = useMemo(
    () => CATEGORY_OPTIONS.filter((c) => c.value !== "all"),
    [],
  );

  useEffect(() => {
    if (!placeId) return;
    loadBookings(placeId, bookingStatus);
  }, [bookingStatus]); // eslint-disable-line

  if (!place) {
    return (
      <div style={{ padding: 24, color: "var(--muted)" }}>
        Админ хэсэг ачаалж байна...
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", padding: "24px 20px" }}>
      <div style={{ marginBottom: 18 }}>
        <h1 style={{ fontSize: 26 }}>Owner/Admin Dashboard</h1>
        <div style={{ color: "var(--muted)", fontSize: 13 }}>
          Газар, зураг, үйлчилгээ, ажилтан, ширээний удирдлага
        </div>
      </div>

      <div
        style={{
          marginBottom: 12,
          display: "flex",
          gap: 8,
          alignItems: "center",
        }}
      >
        <label style={{ marginBottom: 0 }}>Газар сонгох</label>
        <select
          className="input"
          style={{ width: 360 }}
          value={placeId}
          onChange={(e) => setPlaceId(e.target.value)}
        >
          {places.map((p) => (
            <option key={p._id} value={p._id}>
              {p.name}
            </option>
          ))}
        </select>
      </div>

      {msg ? (
        <div style={{ marginBottom: 10, color: "var(--green)", fontSize: 13 }}>
          {msg}
        </div>
      ) : null}
      {err ? (
        <div style={{ marginBottom: 10, color: "var(--red)", fontSize: 13 }}>
          {err}
        </div>
      ) : null}

      <div
        style={{ display: "grid", gridTemplateColumns: "1.1fr 1fr", gap: 18 }}
      >
        <div className="card">
          <h3 style={{ marginBottom: 12 }}>Газарын мэдээлэл</h3>
          <div style={{ display: "grid", gap: 10 }}>
            <input
              className="input"
              value={place.name || ""}
              onChange={(e) => setPlace({ ...place, name: e.target.value })}
              placeholder="Нэр"
            />
            <select
              className="input"
              value={place.category || "salon"}
              onChange={(e) => setPlace({ ...place, category: e.target.value })}
            >
              {categoryOptions.map((c) => (
                <option key={c.key} value={c.key}>
                  {c.icon} {c.label}
                </option>
              ))}
            </select>
            <input
              className="input"
              value={place.address || ""}
              onChange={(e) => setPlace({ ...place, address: e.target.value })}
              placeholder="Хаяг"
            />
            <input
              className="input"
              value={place.phone || ""}
              onChange={(e) => setPlace({ ...place, phone: e.target.value })}
              placeholder="Утас"
            />
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 8,
              }}
            >
              <input
                className="input"
                value={place.location?.lat || ""}
                onChange={(e) =>
                  setPlace({
                    ...place,
                    location: { ...place.location, lat: e.target.value },
                  })
                }
                placeholder="lat"
              />
              <input
                className="input"
                value={place.location?.lng || ""}
                onChange={(e) =>
                  setPlace({
                    ...place,
                    location: { ...place.location, lng: e.target.value },
                  })
                }
                placeholder="lng"
              />
            </div>

            <textarea
              className="input"
              rows={3}
              value={place.description || ""}
              onChange={(e) =>
                setPlace({ ...place, description: e.target.value })
              }
              placeholder="Тайлбар"
              style={{ resize: "vertical" }}
            />

            <button
              className="btn btn-primary"
              onClick={savePlace}
              disabled={savingPlace}
            >
              {savingPlace ? "Хадгалж байна..." : "Мэдээлэл хадгалах"}
            </button>
          </div>
        </div>

        <div className="card">
          <h3 style={{ marginBottom: 12 }}>Зураг (URL)</h3>
          <div style={{ display: "grid", gap: 8 }}>
            {(place.images || []).map((img, i) => (
              <div key={i} style={{ display: "flex", gap: 8 }}>
                <input
                  className="input"
                  value={img}
                  onChange={(e) => {
                    const next = [...(place.images || [])];
                    next[i] = e.target.value;
                    setPlace({ ...place, images: next });
                  }}
                />
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() =>
                    setPlace({
                      ...place,
                      images: (place.images || []).filter(
                        (_, idx) => idx !== i,
                      ),
                    })
                  }
                >
                  Устгах
                </button>
              </div>
            ))}

            <button
              className="btn btn-outline"
              onClick={() =>
                setPlace({ ...place, images: [...(place.images || []), ""] })
              }
            >
              + Зураг нэмэх
            </button>
          </div>
        </div>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 18,
          marginTop: 18,
        }}
      >
        <div className="card">
          <h3 style={{ marginBottom: 12 }}>Үйлчилгээ</h3>
          <div style={{ display: "grid", gap: 8, marginBottom: 12 }}>
            {services.map((s) => (
              <div
                key={s._id}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  border: "1px solid var(--border)",
                  borderRadius: 8,
                  padding: "8px 10px",
                }}
              >
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13 }}>{s.name}</div>
                  <div style={{ fontSize: 11, color: "var(--muted)" }}>
                    {s.duration} мин • ₮{(s.price || 0).toLocaleString()}
                  </div>
                </div>
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() => removeService(s._id)}
                >
                  Устгах
                </button>
              </div>
            ))}
          </div>

          <div style={{ display: "grid", gap: 8 }}>
            <input
              className="input"
              placeholder="Үйлчилгээний нэр"
              value={serviceForm.name}
              onChange={(e) =>
                setServiceForm({ ...serviceForm, name: e.target.value })
              }
            />
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 8,
              }}
            >
              <input
                className="input"
                type="number"
                value={serviceForm.duration}
                onChange={(e) =>
                  setServiceForm({ ...serviceForm, duration: e.target.value })
                }
                placeholder="минут"
              />
              <input
                className="input"
                type="number"
                value={serviceForm.price}
                onChange={(e) =>
                  setServiceForm({ ...serviceForm, price: e.target.value })
                }
                placeholder="үнэ"
              />
            </div>
            <button className="btn btn-primary" onClick={addService}>
              Үйлчилгээ нэмэх
            </button>
          </div>
        </div>

        <div className="card">
          <h3 style={{ marginBottom: 12 }}>Ажилтан</h3>
          <div style={{ display: "grid", gap: 8, marginBottom: 12 }}>
            {staffs.map((s) => (
              <div
                key={s._id}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  border: "1px solid var(--border)",
                  borderRadius: 8,
                  padding: "8px 10px",
                }}
              >
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13 }}>{s.name}</div>
                  <div style={{ fontSize: 11, color: "var(--muted)" }}>
                    {s.role}
                  </div>
                </div>
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() => removeStaff(s._id)}
                >
                  Устгах
                </button>
              </div>
            ))}
          </div>

          <div style={{ display: "grid", gap: 8 }}>
            <input
              className="input"
              placeholder="Нэр"
              value={staffForm.name}
              onChange={(e) =>
                setStaffForm({ ...staffForm, name: e.target.value })
              }
            />
            <input
              className="input"
              placeholder="Role (barber, artist...)"
              value={staffForm.role}
              onChange={(e) =>
                setStaffForm({ ...staffForm, role: e.target.value })
              }
            />
            <input
              className="input"
              placeholder="Profile image URL"
              value={staffForm.profileImage}
              onChange={(e) =>
                setStaffForm({ ...staffForm, profileImage: e.target.value })
              }
            />
            <button className="btn btn-primary" onClick={addStaff}>
              Ажилтан нэмэх
            </button>
          </div>
        </div>
      </div>

      <div className="card" style={{ marginTop: 18 }}>
        <h3 style={{ marginBottom: 12 }}>Ширээ (Billiard / Restaurant)</h3>

        <div style={{ display: "grid", gap: 8, marginBottom: 12 }}>
          {(place.tables || []).map((t) => (
            <div
              key={t._id}
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                border: "1px solid var(--border)",
                borderRadius: 8,
                padding: "8px 10px",
              }}
            >
              <div>
                <div style={{ fontWeight: 600, fontSize: 13 }}>{t.name}</div>
                <div style={{ fontSize: 11, color: "var(--muted)" }}>
                  {t.type} • {t.row}-{t.col} • {t.capacity} хүн
                </div>
              </div>
              <button
                className="btn btn-danger btn-sm"
                onClick={() => removeTable(t._id)}
              >
                Устгах
              </button>
            </div>
          ))}
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(5, minmax(0, 1fr))",
            gap: 8,
          }}
        >
          <input
            className="input"
            placeholder="Нэр"
            value={tableForm.name}
            onChange={(e) =>
              setTableForm({ ...tableForm, name: e.target.value })
            }
          />
          <select
            className="input"
            value={tableForm.type}
            onChange={(e) =>
              setTableForm({ ...tableForm, type: e.target.value })
            }
          >
            <option value="regular">regular</option>
            <option value="vip">vip</option>
            <option value="hall">hall</option>
          </select>
          <input
            className="input"
            placeholder="Row"
            value={tableForm.row}
            onChange={(e) =>
              setTableForm({ ...tableForm, row: e.target.value })
            }
          />
          <input
            className="input"
            type="number"
            placeholder="Col"
            value={tableForm.col}
            onChange={(e) =>
              setTableForm({
                ...tableForm,
                col: parseNumber(e.target.value, 1),
              })
            }
          />
          <input
            className="input"
            type="number"
            placeholder="Capacity"
            value={tableForm.capacity}
            onChange={(e) =>
              setTableForm({
                ...tableForm,
                capacity: parseNumber(e.target.value, 2),
              })
            }
          />
        </div>

        <div style={{ marginTop: 10 }}>
          <button className="btn btn-outline" onClick={addTable}>
            + Ширээ локал нэмэх
          </button>
          <span style={{ marginLeft: 10, fontSize: 12, color: "var(--muted)" }}>
            Ширээ өөрчлөлтөө хадгалахын тулд дээрх "Мэдээлэл хадгалах" товч
            дарна.
          </span>
        </div>
      </div>

      <div className="card" style={{ marginTop: 18 }}>
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: 12,
          }}
        >
          <h3>Захиалга удирдлага</h3>
          <select
            className="input"
            style={{ width: 180 }}
            value={bookingStatus}
            onChange={(e) => setBookingStatus(e.target.value)}
          >
            <option value="all">Бүх төлөв</option>
            <option value="pending">Хүлээгдэж буй</option>
            <option value="confirmed">Баталгаажсан</option>
            <option value="cancelled">Цуцлагдсан</option>
            <option value="completed">Дууссан</option>
          </select>
        </div>

        {bookingLoading ? (
          <div style={{ color: "var(--muted)", fontSize: 13 }}>
            Захиалга ачаалж байна...
          </div>
        ) : bookings.length === 0 ? (
          <div style={{ color: "var(--muted)", fontSize: 13 }}>
            Захиалга байхгүй байна.
          </div>
        ) : (
          <div style={{ display: "grid", gap: 8 }}>
            {bookings.map((b) => (
              <div
                key={b._id}
                style={{
                  border: "1px solid var(--border)",
                  borderRadius: 10,
                  padding: "10px 12px",
                  display: "flex",
                  justifyContent: "space-between",
                  gap: 10,
                  alignItems: "center",
                }}
              >
                <div>
                  <div style={{ fontSize: 14, fontWeight: 600 }}>
                    {b.userId?.name} • {b.serviceId?.name}
                  </div>
                  <div style={{ fontSize: 12, color: "var(--muted)" }}>
                    {new Date(b.datetime).toLocaleString("mn-MN")} •{" "}
                    {STATUS_LABEL[b.status]}
                    {b.staffId ? ` • ${b.staffId.name}` : ""}
                    {b.tableId ? " • Ширээ" : ""}
                  </div>
                </div>

                <div style={{ display: "flex", gap: 6 }}>
                  {b.status === "pending" ? (
                    <button
                      className="btn btn-primary btn-sm"
                      onClick={() => confirmBooking(b._id)}
                    >
                      Батлах
                    </button>
                  ) : null}
                  {["pending", "confirmed"].includes(b.status) ? (
                    <button
                      className="btn btn-danger btn-sm"
                      onClick={() => cancelBooking(b._id)}
                    >
                      Цуцлах
                    </button>
                  ) : null}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
